@page "/settings"
@using sv_cd22fae21ad843febf1839de8030d224.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(ActiveSection == section.Key ? "active" : "")"
                            @onclick="() => ActiveSection = section.Key">
                        <span class="section-icon">@section.Icon</span>
                        @section.Label
                    </button>
                </li>
            }
        </ul>
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        <!-- Toast notification -->
        @if (_showToast)
        {
            <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                <span>@_toastMessage</span>
                <button class="btn-close btn-close-white btn-sm" @onclick="() => _showToast = false"></button>
            </div>
        }
    </div>
</div>

<!-- Session revoke confirmation modal -->
@if (_showRevokeConfirm)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong> in <strong>@_sessionToRevoke?.Location</strong>?</p>
                    <p class="text-muted mb-0">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    // ── Section navigation ──────────────────────────────────────────────
    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // ── Toast ───────────────────────────────────────────────────────────
    private bool _showToast;
    private string _toastMessage = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile state ───────────────────────────────────────────────────
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _profileSaving;

    // ── Notification state ──────────────────────────────────────────────
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "support"];
    private HashSet<string> _mutedChannels = new();
    private bool _notifSaving;

    // ── Security state ──────────────────────────────────────────────────
    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _passwordSaving;
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // ── Appearance state ────────────────────────────────────────────────
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _appearanceSaving;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    // ── Lifecycle ───────────────────────────────────────────────────────
    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettingsAsync();
        _loading = false;
    }

    private async Task LoadAllSettingsAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        ApplyProfile(await profileTask);
        ApplyNotificationPrefs(await notifsTask);
        _security = await securityTask;
        ApplyAppearance(await appearanceTask);
    }

    // ── Toast helper ────────────────────────────────────────────────────
    private async Task ShowToastAsync(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _showToast = true;
        StateHasChanged();

        try
        {
            await Task.Delay(4000, token);
            _showToast = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile ─────────────────────────────────────────────────────────
    private void ApplyProfile(UserProfile p)
    {
        _savedProfile = p;
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private bool ProfileHasChanges =>
        _savedProfile is not null &&
        (_displayName != _savedProfile.DisplayName ||
         _email != _savedProfile.Email ||
         _avatarUrl != _savedProfile.AvatarUrl ||
         _bio != _savedProfile.Bio);

    private async Task SaveProfileAsync()
    {
        _profileSaving = true;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            await ShowToastAsync("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            await ShowToastAsync($"Failed to save profile: {ex.Message}", true);
        }
        finally
        {
            _profileSaving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null) ApplyProfile(_savedProfile);
    }

    // ── Notifications ───────────────────────────────────────────────────
    private void ApplyNotificationPrefs(NotificationPrefs n)
    {
        _emailNotifications = n.EmailNotifications;
        _pushNotifications = n.PushNotifications;
        _weeklyDigest = n.WeeklyDigest;
        _mutedChannels = new HashSet<string>(n.MutedChannels);
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveNotificationPrefsAsync()
    {
        _notifSaving = true;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            await ShowToastAsync("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            await ShowToastAsync($"Failed to save preferences: {ex.Message}", true);
        }
        finally
        {
            _notifSaving = false;
        }
    }

    // ── Security ────────────────────────────────────────────────────────
    private async Task ChangePasswordAsync()
    {
        if (_newPassword != _confirmPassword)
        {
            await ShowToastAsync("Passwords do not match.", true);
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            await ShowToastAsync("New password must be at least 8 characters.", true);
            return;
        }

        _passwordSaving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            _security = await SettingsService.GetSecuritySettingsAsync();
            await ShowToastAsync("Password updated successfully.");
        }
        catch (Exception ex)
        {
            await ShowToastAsync($"Password change failed: {ex.Message}", true);
        }
        finally
        {
            _passwordSaving = false;
        }
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private void CancelRevoke()
    {
        _showRevokeConfirm = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _security = await SettingsService.GetSecuritySettingsAsync();
            _showRevokeConfirm = false;
            _sessionToRevoke = null;
            await ShowToastAsync("Session revoked.");
        }
        catch (Exception ex)
        {
            await ShowToastAsync($"Failed to revoke session: {ex.Message}", true);
        }
        finally
        {
            _revoking = false;
        }
    }

    // ── Appearance ──────────────────────────────────────────────────────
    private void ApplyAppearance(AppearanceSettings a)
    {
        _theme = a.Theme;
        _fontSize = a.FontSize;
        _language = a.Language;
        _compactMode = a.CompactMode;
    }

    private async Task SaveAppearanceAsync()
    {
        _appearanceSaving = true;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            await ShowToastAsync("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            await ShowToastAsync($"Failed to save appearance: {ex.Message}", true);
        }
        finally
        {
            _appearanceSaving = false;
        }
    }

    private string PreviewBackground => _theme switch
    {
        "Dark" => "#1e1e1e",
        "Light" => "#ffffff",
        _ => "#f0f0f0"
    };

    private string PreviewTextColor => _theme == "Dark" ? "#d4d4d4" : "#1e1e1e";

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    // ── Render fragments ────────────────────────────────────────────────
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <h3 class="section-heading">Profile</h3>
        <p class="text-muted">Manage your public profile information.</p>
        <hr />

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label" for="displayName">Display Name</label>
                    <input id="displayName" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label" for="email">Email</label>
                    <input id="email" type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label" for="bio">Bio</label>
                    <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4">
                <div class="avatar-preview-area text-center">
                    <label class="form-label">Avatar Preview</label>
                    <div class="avatar-frame mx-auto mb-2">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">👤</div>
                        }
                    </div>
                    <small class="text-muted text-break d-block mb-2">@_avatarUrl</small>
                    <div class="mb-3">
                        <input class="form-control form-control-sm" placeholder="Avatar URL" @bind="_avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-2">
            <button class="btn btn-primary" @onclick="SaveProfileAsync" disabled="@(_profileSaving || !ProfileHasChanges)">
                @if (_profileSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@(!ProfileHasChanges)">
                Discard Changes
            </button>
        </div>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <h3 class="section-heading">Notifications</h3>
        <p class="text-muted">Choose how and when you want to be notified.</p>
        <hr />

        <div class="mb-4">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <h5>Muted Channels</h5>
        <p class="text-muted">Select channels to mute. You won't receive notifications from muted channels.</p>
        <div class="row">
            @foreach (var channel in _allChannels)
            {
                <div class="col-md-6 mb-2">
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">
                            # @channel
                        </label>
                    </div>
                </div>
            }
        </div>

        <div class="mt-4">
            <button class="btn btn-primary" @onclick="SaveNotificationPrefsAsync" disabled="@_notifSaving">
                @if (_notifSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </div>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <h3 class="section-heading">Security</h3>
        <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>
        <hr />

        <!-- Change Password panel -->
        <div class="card mb-4">
            <div class="card-header d-flex align-items-center justify-content-between"
                 style="cursor: pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <strong>Change Password</strong>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    @if (_security?.LastPasswordChange is not null)
                    {
                        <p class="text-muted mb-3">
                            Last changed: @_security.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </p>
                    }
                    <div class="row g-3">
                        <div class="col-md-4">
                            <label class="form-label" for="curPwd">Current Password</label>
                            <input id="curPwd" type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label" for="newPwd">New Password</label>
                            <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label" for="confirmPwd">Confirm Password</label>
                            <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                    </div>
                    <button class="btn btn-primary mt-3" @onclick="ChangePasswordAsync" disabled="@_passwordSaving">
                        @if (_passwordSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body d-flex align-items-center justify-content-between">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="mt-1">
                        @if (_security?.TwoFactorEnabled == true)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark">Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@(_security?.TwoFactorEnabled ?? false)" disabled />
                </div>
            </div>
        </div>

        <!-- Active Sessions -->
        <h5>Active Sessions</h5>
        @if (_security?.Sessions is { Count: > 0 })
        {
            <div class="table-responsive">
                <table class="table table-hover align-middle">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th class="text-end">Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var (session, index) in _security.Sessions.Select((s, i) => (s, i)))
                        {
                            var isCurrent = index == 0;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-info ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                                <td class="text-end">
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => RequestRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
        else
        {
            <p class="text-muted">No active sessions found.</p>
        }
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <h3 class="section-heading">Appearance</h3>
        <p class="text-muted">Customize the look and feel of the application.</p>
        <hr />

        <div class="row">
            <div class="col-md-7">
                <!-- Theme -->
                <div class="mb-4">
                    <label class="form-label fw-bold">Theme</label>
                    <div class="d-flex gap-3">
                        @foreach (var t in _themes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
                                       value="@t" checked="@(_theme == t)"
                                       @onchange="() => _theme = t" />
                                <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Font size -->
                <div class="mb-4">
                    <label class="form-label fw-bold">Font Size</label>
                    <div class="d-flex gap-3">
                        @foreach (var fs in _fontSizes)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{fs}")"
                                       value="@fs" checked="@(_fontSize == fs)"
                                       @onchange="() => _fontSize = fs" />
                                <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Language -->
                <div class="mb-4">
                    <label class="form-label fw-bold" for="langSelect">Language</label>
                    <select id="langSelect" class="form-select" style="max-width: 250px;" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <!-- Compact mode -->
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">
                            <strong>Compact Mode</strong>
                            <small class="d-block text-muted">Reduce spacing and padding throughout the app</small>
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAppearanceAsync" disabled="@_appearanceSaving">
                    @if (_appearanceSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save
                </button>
            </div>

            <!-- Live preview -->
            <div class="col-md-5">
                <label class="form-label fw-bold">Live Preview</label>
                <div class="preview-card"
                     style="background: @PreviewBackground; color: @PreviewTextColor; font-size: @PreviewFontSize; padding: @(_compactMode ? "0.5rem" : "1.25rem");">
                    <div class="preview-header" style="margin-bottom: @(_compactMode ? "0.25rem" : "0.75rem");">
                        <strong>Dashboard</strong>
                    </div>
                    <div class="preview-line" style="margin-bottom: @(_compactMode ? "0.15rem" : "0.5rem");">
                        Welcome back! Here's your activity summary.
                    </div>
                    <div class="preview-card-inner"
                         style="background: @(_theme == "Dark" ? "#2d2d2d" : "#f8f9fa"); border-radius: 6px; padding: @(_compactMode ? "0.4rem" : "0.75rem"); margin-bottom: @(_compactMode ? "0.25rem" : "0.5rem");">
                        <div style="font-weight: 600; margin-bottom: 0.25rem;">📊 Stats</div>
                        <div>Tasks completed: 12</div>
                        <div>Pending reviews: 3</div>
                    </div>
                    <div class="d-flex gap-2">
                        <span class="badge" style="background: #1b6ec2;">Primary</span>
                        <span class="badge" style="background: #198754;">Success</span>
                        <span class="badge" style="background: #dc3545;">Alert</span>
                    </div>
                </div>
            </div>
        </div>
    };
}

