+                        <div class="col-md-4">
+                            <label class="form-label" for="confirmPwd">Confirm Password</label>
+                            <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
+                        </div>
+                    </div>
+                    <button class="btn btn-primary mt-3" @onclick="ChangePasswordAsync" disabled="@_passwordSaving">
+                        @if (_passwordSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
+                        Update Password
+                    </button>
+                </div>
+            }
+        </div>
+
+        <!-- Two-Factor Authentication -->
+        <div class="card mb-4">
+            <div class="card-body d-flex align-items-center justify-content-between">
+                <div>
+                    <strong>Two-Factor Authentication</strong>
+                    <div class="mt-1">
+                        @if (_security?.TwoFactorEnabled == true)
+                        {
+                            <span class="badge bg-success">Enabled</span>
+                        }
+                        else
+                        {
+                            <span class="badge bg-warning text-dark">Disabled</span>
+                        }
+                    </div>
+                </div>
+                <div class="form-check form-switch">
+                    <input class="form-check-input" type="checkbox" id="twoFactor"
+                           checked="@(_security?.TwoFactorEnabled ?? false)" disabled />
+                </div>
+            </div>
+        </div>
+
+        <!-- Active Sessions -->
+        <h5>Active Sessions</h5>
+        @if (_security?.Sessions is { Count: > 0 })
+        {
+            <div class="table-responsive">
+                <table class="table table-hover align-middle">
+                    <thead class="table-light">
+                        <tr>
+                            <th>Device</th>
+                            <th>Location</th>
+                            <th>Last Active</th>
+                            <th class="text-end">Action</th>
+                        </tr>
+                    </thead>
+                    <tbody>
+                        @foreach (var (session, index) in _security.Sessions.Select((s, i) => (s, i)))
+                        {
+                            var isCurrent = index == 0;
+                            <tr>
+                                <td>
+                                    @session.Device
+                                    @if (isCurrent)
+                                    {
+                                        <span class="badge bg-info ms-1">Current</span>
+                                    }
+                                </td>
+                                <td>@session.Location</td>
+                                <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
+                                <td class="text-end">
+                                    @if (!isCurrent)
+                                    {
+                                        <button class="btn btn-outline-danger btn-sm"
+                                                @onclick="() => RequestRevoke(session)">
+                                            Revoke
+                                        </button>
+                                    }
+                                </td>
+                            </tr>
+                        }
+                    </tbody>
+                </table>
+            </div>
+        }
+        else
+        {
+            <p class="text-muted">No active sessions found.</p>
+        }
+    };
+
+    private RenderFragment RenderAppearanceSection() => __builder =>
+    {
+        <h3 class="section-heading">Appearance</h3>
+        <p class="text-muted">Customize the look and feel of the application.</p>
+        <hr />
+
+        <div class="row">
+            <div class="col-md-7">
+                <!-- Theme -->
+                <div class="mb-4">
+                    <label class="form-label fw-bold">Theme</label>
+                    <div class="d-flex gap-3">
+                        @foreach (var t in _themes)
+                        {
+                            <div class="form-check">
+                                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{t}")"
+                                       value="@t" checked="@(_theme == t)"
+                                       @onchange="() => _theme = t" />
+                                <label class="form-check-label" for="@($"theme-{t}")">@t</label>
+                            </div>
+                        }
+                    </div>
+                </div>
+
+                <!-- Font size -->
+                <div class="mb-4">
+                    <label class="form-label fw-bold">Font Size</label>
+                    <div class="d-flex gap-3">
+                        @foreach (var fs in _fontSizes)
+                        {
+                            <div class="form-check">
+                                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{fs}")"
+                                       value="@fs" checked="@(_fontSize == fs)"
+                                       @onchange="() => _fontSize = fs" />
+                                <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
+                            </div>
+                        }
+                    </div>
+                </div>
+
+                <!-- Language -->
+                <div class="mb-4">
+                    <label class="form-label fw-bold" for="langSelect">Language</label>
+                    <select id="langSelect" class="form-select" style="max-width: 250px;" @bind="_language">
+                        @foreach (var lang in _languages)
+                        {
+                            <option value="@lang">@lang</option>
+                        }
+                    </select>
+                </div>
+
+                <!-- Compact mode -->
+                <div class="mb-4">
+                    <div class="form-check form-switch">
+                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
+                        <label class="form-check-label" for="compactMode">
+                            <strong>Compact Mode</strong>
+                            <small class="d-block text-muted">Reduce spacing and padding throughout the app</small>
+                        </label>
+                    </div>
+                </div>
+
+                <button class="btn btn-primary" @onclick="SaveAppearanceAsync" disabled="@_appearanceSaving">
+                    @if (_appearanceSaving) { <span class="spinner-border spinner-border-sm me-1"></span> }
+                    Save
+                </button>
+            </div>
+
+            <!-- Live preview -->
+            <div class="col-md-5">
+                <label class="form-label fw-bold">Live Preview</label>
+                <div class="preview-card"
+                     style="background: @PreviewBackground; color: @PreviewTextColor; font-size: @PreviewFontSize; padding: @(_compactMode ? "0.5rem" : "1.25rem");">
+                    <div class="preview-header" style="margin-bottom: @(_compactMode ? "0.25rem" : "0.75rem");">
+                        <strong>Dashboard</strong>
+                    </div>
+                    <div class="preview-line" style="margin-bottom: @(_compactMode ? "0.15rem" : "0.5rem");">
+                        Welcome back! Here's your activity summary.
+                    </div>
+                    <div class="preview-card-inner"
+                         style="background: @(_theme == "Dark" ? "#2d2d2d" : "#f8f9fa"); border-radius: 6px; padding: @(_compactMode ? "0.4rem" : "0.75rem"); margin-bottom: @(_compactMode ? "0.25rem" : "0.5rem");">
+                        <div style="font-weight: 600; margin-bottom: 0.25rem;">📊 Stats</div>
+                        <div>Tasks completed: 12</div>
+                        <div>Pending reviews: 3</div>
+                    </div>
+                    <div class="d-flex gap-2">
+                        <span class="badge" style="background: #1b6ec2;">Primary</span>
+                        <span class="badge" style="background: #198754;">Success</span>
+                        <span class="badge" style="background: #dc3545;">Alert</span>
+                    </div>
+                </div>
+            </div>
+        </div>
+    };
+}
